<template>
    <div class="demo-content">
        <h1>mapbox添加点线面</h1>
        <h4>Tip:以下地图坐标从高德地图拾取,需要进行坐标转换</h4>
        <h2>添加点</h2>
        <div class="field">
            <div class="field-left">
                <pre>
                    <code-copy :code="pointCode" :btnClssName="'copy-btn1'"></code-copy>
                    <code>{{pointCode}}</code>
                </pre>
            </div>
            <div class="field-right">
                <base-map :mapOptions="mapOptions1" :hasThreeModel="false" @getMap="getMap1($event)"></base-map>
            </div>
        </div>
        <h2>添加线</h2>
        <div class="field">
            <div class="field-left">
                <pre>
                    <code-copy :code="lineCode" :btnClssName="'copy-btn2'"></code-copy>
                    <code>{{lineCode}}</code>
                </pre>
            </div>
            <div class="field-right">
