        let map2 = reactive(null);
        let map3 = reactive(null);

        const getMap1 = data => {
            map1 = data;
            addPonitLayer(map1);
        };

        const getMap2 = data => {
            map2 = data;
            addLineLayer(map2);
        };

        const getMap3 = data => {
            map3 = data;
            addPolygonLayer(map3);
        };

        const pointCode = ref(`// 添加点        
const addPonitLayer = (map) => {
    const point = [118.77889334732174, 32.043807683008296];
    const pointSourceId = "pointSourceId";
    const pointLayerId = "pointLayerId";
    const features = [];
    const temp2 = {
        type: "Feature",
        geometry: {
            type: "Point",
            coordinates: point
        },
        properties: {
            icon: "test"
        }
    };
    features.push(temp2);
    const featureCollection = {
        type: "FeatureCollection",
        features
    };
    if (map.getSource(pointSourceId)) {
        map.getSource(pointSourceId).setData(featureCollection);
    } else {
        map.addSource(pointSourceId, {
            type: "geojson",
            data: featureCollection
        });
        map.addLayer({
            id: pointLayerId,
            type: "symbol",
            source: pointSourceId,
            layout: {
                "icon-image": ["get", "icon"],
                "icon-ignore-placement": true,
                "icon-allow-overlap": true,
                "icon-size": 1
            }
        });
    }
};`);

        const lineCode = ref(`// 添加线
