        const bounds = new mapboxgl.LngLatBounds(
            [bbox[0], bbox[1]],
            [bbox[2], bbox[3]]
        );
        map.fitBounds(bounds, {
            padding: { top: 50, bottom: 50, left: 50, right: 50 }
        });
    }
};`);

