            [bbox[2], bbox[3]]
        );
        map.fitBounds(bounds, {
            padding: { top: 50, bottom: 50, left: 50, right: 50 }
        });
    }
};`);

        // 添加点
        const addPonitLayer = map => {
            const point = [118.77889334732174, 32.043807683008296];
            const pointSourceId = "pointSourceId";
            const pointLayerId = "pointLayerId";
            const features = [];
            const temp2 = {
                type: "Feature",
                geometry: {
                    type: "Point",
                    coordinates: point
                },
                properties: {
                    icon: "test"
                }
