            features.push(temp2);
            const featureCollection = {
                type: "FeatureCollection",
                features
            };
            if (map.getSource(pointSourceId)) {
                map.getSource(pointSourceId).setData(featureCollection);
            } else {
                map.addSource(pointSourceId, {
