                map.fitBounds(bounds, {
                    padding: { top: 50, bottom: 50, left: 50, right: 50 }
                });
            }
        };

        onMounted(() => {
            Utils.highlightCode();
        });

        onUpdated(() => {
            Utils.highlightCode();
        });

        return {
            mapOptions1,
            mapOptions2,
            mapOptions3,
            getMap1,
            getMap2,
            getMap3,
            addPonitLayer,
            addLineLayer,
            addPolygonLayer,
            pointCode,
            lineCode,
            polygonCode
        };
