};
</script>

<style lang="scss" scoped>
.demo-content {
    width: 100%;
    height: 100%;
    padding: 16px;
    overflow: auto;

    .field {
        display: flex;
        width: 100%;
        height: 400px;
        margin: 16px 0;

        .field-left {
            flex: 1;
            height: 100%;
            width: 0;

            pre {
                margin: 0;
                padding: 0;
                height: 100%;
                display: flex;
                width: 100%;
                position: relative;

                code {
                    width: 100%;
                }
            }
        }

        .field-right {
            margin-left: 16px;
            width: 50%;
            height: 100%;
        }
    }
}
</style>
